import React, { useState } from 'react';
import axios from 'axios';

const StartPage = ({ onQuizStart }) => {
  const [formData, setFormData] = useState({
    teamName: '',
    teamLeaderName: '',
    teamLeaderEmail: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const validateEmail = (email) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.teamName.trim() || !formData.teamLeaderName.trim() || !formData.teamLeaderEmail.trim()) {
      setError('All fields are required');
      return;
    }

    if (!validateEmail(formData.teamLeaderEmail)) {
      setError('Please enter a valid email');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const response = await axios.post('http://localhost:8000/start-quiz', {
        team_name: formData.teamName,
        team_leader_name: formData.teamLeaderName,
        team_leader_email: formData.teamLeaderEmail
      });

      onQuizStart(response.data.quiz_id, formData);

    } catch (err) {
      setError(err.response?.data?.detail || 'Failed to start quiz');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: 'white'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '400px',
        padding: '20px'
      }}>
        <h1 style={{ 
          fontSize: '32px', 
          marginBottom: '8px', 
          color: '#1a1a1a',
          fontWeight: '700',
          letterSpacing: '-0.5px'
        }}>
          Quiz Registration
        </h1>
        <p style={{ 
          color: '#4a5568', 
          marginBottom: '32px', 
          fontSize: '16px',
          fontWeight: '400'
        }}>
          25 questions • 30 minutes
        </p>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '24px' }}>
            <label style={{ 
              display: 'block', 
              marginBottom: '8px', 
              color: '#2d3748', 
              fontSize: '15px',
              fontWeight: '600'
            }}>
              Team Name
            </label>
            <input
              type="text"
              value={formData.teamName}
              onChange={(e) => setFormData({...formData, teamName: e.target.value})}
              style={{
                width: '100%',
                padding: '12px 14px',
                border: '1px solid #cbd5e0',
                borderRadius: '6px',
                fontSize: '16px',
                backgroundColor: 'white',
                color: '#1a202c'
              }}
              placeholder="Enter your team name"
            />
          </div>

          <div style={{ marginBottom: '24px' }}>
            <label style={{ 
              display: 'block', 
              marginBottom: '8px', 
              color: '#2d3748', 
              fontSize: '15px',
              fontWeight: '600'
            }}>
              Team Leader Name
            </label>
            <input
              type="text"
              value={formData.teamLeaderName}
              onChange={(e) => setFormData({...formData, teamLeaderName: e.target.value})}
              style={{
                width: '100%',
                padding: '12px 14px',
                border: '1px solid #cbd5e0',
                borderRadius: '6px',
                fontSize: '16px',
                backgroundColor: 'white',
                color: '#1a202c'
              }}
              placeholder="Enter leader's full name"
            />
          </div>

          <div style={{ marginBottom: '28px' }}>
            <label style={{ 
              display: 'block', 
              marginBottom: '8px', 
              color: '#2d3748', 
              fontSize: '15px',
              fontWeight: '600'
            }}>
              Email Address
            </label>
            <input
              type="email"
              value={formData.teamLeaderEmail}
              onChange={(e) => setFormData({...formData, teamLeaderEmail: e.target.value})}
              style={{
                width: '100%',
                padding: '12px 14px',
                border: '1px solid #cbd5e0',
                borderRadius: '6px',
                fontSize: '16px',
                backgroundColor: 'white',
                color: '#1a202c'
              }}
              placeholder="name@example.com"
            />
          </div>

          {error && (
            <div style={{ 
              color: '#c53030', 
              marginBottom: '20px', 
              fontSize: '14px',
              padding: '10px',
              backgroundColor: '#fff5f5',
              borderRadius: '6px',
              border: '1px solid #feb2b2'
            }}>
              ⚠️ {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%',
              padding: '14px',
              backgroundColor: loading ? '#718096' : '#1a202c',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              fontSize: '16px',
              fontWeight: '600',
              cursor: loading ? 'not-allowed' : 'pointer',
              transition: 'background-color 0.2s'
            }}
          >
            {loading ? 'Starting...' : 'Continue to Rules →'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default StartPage;
